  });

  test("has unique index on (snapshot_id, message_id)", () => {
    const indexes = rawDb
      .prepare("SELECT name, [unique] FROM sqlite_master WHERE type = 'index' AND tbl_name = 'message_edits'")
      .all() as Array<{ name: string; unique: number }>;

    const uniqueIdx = indexes.find((i) => i.name === "idx_message_edits_snapshot_message");
    expect(uniqueIdx).toBeDefined();
  });

  test("foreign key references imports(id) and conversation_snapshots(id) with CASCADE", () => {
    const fks = rawDb
      .prepare("PRAGMA foreign_key_list('message_edits')")
      .all() as Array<{ table: string; from: string; to: string; on_delete: string }>;

