import { and, count, eq } from "drizzle-orm";
import { db } from "../db/client.js";
import { messageEdits } from "../db/schema.js";
import type { MessageEditRecord } from "../db/schema.js";

export function saveMessageEdit(
  importId: string,
  snapshotId: string,
  messageId: string,
  editedBlocksJson: string,
  annotation?: string,
): MessageEditRecord {
  const now = new Date().toISOString();
  const id = crypto.randomUUID();

  db.insert(messageEdits)
    .values({
      id,
      importId,
      snapshotId,
      messageId,
      editedBlocksJson,
      annotation: annotation ?? null,
      createdAt: now,
      updatedAt: now,
    })
    .onConflictDoUpdate({
      target: [messageEdits.snapshotId, messageEdits.messageId],
      set: {
        editedBlocksJson,
        annotation: annotation ?? null,
        updatedAt: now,
      },
    })
    .run();

  // Return the current state (may be the upserted row with a different id)
  const row = db
    .select()
    .from(messageEdits)
    .where(
      and(
        eq(messageEdits.snapshotId, snapshotId),
        eq(messageEdits.messageId, messageId),
      ),
    )
    .get();

  return row!;
}

export function getMessageEdit(
  snapshotId: string,
  messageId: string,
): MessageEditRecord | undefined {
  return db
    .select()
    .from(messageEdits)
    .where(
      and(
        eq(messageEdits.snapshotId, snapshotId),
        eq(messageEdits.messageId, messageId),
      ),
    )
    .get();
}

export function listMessageEdits(snapshotId: string): MessageEditRecord[] {
  return db
    .select()
    .from(messageEdits)
    .where(eq(messageEdits.snapshotId, snapshotId))
    .all();
}

export function deleteMessageEdit(
  snapshotId: string,
  messageId: string,
): boolean {
  const result = db
    .delete(messageEdits)
    .where(
      and(
        eq(messageEdits.snapshotId, snapshotId),
        eq(messageEdits.messageId, messageId),
      ),
    )
    .run();

  return result.changes > 0;
}

export function deleteAllEditsForSnapshot(snapshotId: string): number {
  const result = db
    .delete(messageEdits)
    .where(eq(messageEdits.snapshotId, snapshotId))
    .run();

  return result.changes;
}

export function countEdits(snapshotId: string): number {
  const row = db
    .select({ value: count() })
    .from(messageEdits)
    .where(eq(messageEdits.snapshotId, snapshotId))
    .get();

  return row?.value ?? 0;
}

import type { ConversationSnapshot } from "@chat-exporter/shared";
import { eq } from "drizzle-orm";
import { db, withTransaction } from "../db/client.js";
import { conversationSnapshots } from "../db/schema.js";

type SnapshotRow = typeof conversationSnapshots.$inferSelect;

function toApiSnapshot(row: SnapshotRow): ConversationSnapshot {
  return {
    id: row.id,
    importId: row.importId,
    label: row.label,
    isActive: row.isActive === 1,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}

export function createSnapshot(
  importId: string,
  label: string,
): ConversationSnapshot {
  const id = crypto.randomUUID();
  const now = new Date().toISOString();

  db.insert(conversationSnapshots)
    .values({
      id,
      importId,
      label,
      isActive: 0,
      createdAt: now,
      updatedAt: now,
    })
    .run();

  return { id, importId, label, isActive: false, createdAt: now, updatedAt: now };
}

export function listSnapshots(importId: string): ConversationSnapshot[] {
  const rows = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.importId, importId))
    .orderBy(conversationSnapshots.createdAt)
    .all();

  return rows.map(toApiSnapshot);
}

export function getActiveSnapshot(
  importId: string,
): ConversationSnapshot | null {
  const row = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.importId, importId))
    .all()
    .find((r) => r.isActive === 1);

  return row ? toApiSnapshot(row) : null;
}

export function activateSnapshot(
  snapshotId: string,
): ConversationSnapshot {
  return withTransaction(() => {
    const snapshot = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .get();

    if (!snapshot) {
      throw new Error(`Snapshot not found: ${snapshotId}`);
    }

    const now = new Date().toISOString();

    // Deactivate all snapshots of the same import
    db.update(conversationSnapshots)
      .set({ isActive: 0, updatedAt: now })
      .where(eq(conversationSnapshots.importId, snapshot.importId))
      .run();

    // Activate this snapshot
    db.update(conversationSnapshots)
      .set({ isActive: 1, updatedAt: now })
      .where(eq(conversationSnapshots.id, snapshotId))
      .run();

    const updated = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .get()!;

    return toApiSnapshot(updated);
  });
}

export function deactivateAllSnapshots(importId: string): void {
  withTransaction(() => {
    const now = new Date().toISOString();
    db.update(conversationSnapshots)
      .set({ isActive: 0, updatedAt: now })
      .where(eq(conversationSnapshots.importId, importId))
      .run();
  });
}

export function deleteSnapshot(snapshotId: string): boolean {
  const result = db
    .delete(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .run();

  return result.changes > 0;
}

export function renameSnapshot(
  snapshotId: string,
  label: string,
): ConversationSnapshot {
  const now = new Date().toISOString();

  db.update(conversationSnapshots)
    .set({ label, updatedAt: now })
    .where(eq(conversationSnapshots.id, snapshotId))
    .run();

  const updated = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .get();

  if (!updated) {
    throw new Error(`Snapshot not found: ${snapshotId}`);
  }

  return toApiSnapshot(updated);
}

