  4→} from "@chat-exporter/shared";
  5→import { useQuery, useQueryClient } from "@tanstack/react-query";
  6→import { useState } from "react";
  7→import {
  8→  adjustableViews,
  9→  type ViewMode,
 10→} from "@/components/format-workspace/types";
 11→import { useRuleExplanations } from "@/components/format-workspace/use-rule-explanations";
 12→import { orpc } from "@/lib/orpc";
 13→import { demoteFormatRule, promoteFormatRule, rpc } from "@/lib/rpc";
 14→
 15→function errorMsg(error: unknown, fallback: string): string {
 16→  return error instanceof Error ? error.message : fallback;
 17→}
 18→
 19→function removeKey(
 20→  rec: Record<string, boolean>,
 21→  key: string,
 22→): Record<string, boolean> {
 23→  const next = { ...rec };
 24→  delete next[key];
 25→  return next;
 26→}
 27→
 28→export function useFormatRules(view: ViewMode, jobId: string) {
 29→  const queryClient = useQueryClient();
 30→  const isAdjustableView = adjustableViews.has(view);
 31→  const rulesQuery = useQuery({
 32→    ...orpc.rules.list.queryOptions({
 33→      input: { importId: jobId, format: view },
 34→    }),
 35→    enabled: isAdjustableView,
 36→  });
 37→  const activeRules: FormatRule[] = rulesQuery.data ?? [];
 38→
 39→  const [disablingRuleById, setDisablingRuleById] = useState<
 40→    Record<string, boolean>
 41→  >({});
 42→  const [promotingRuleById, setPromotingRuleById] = useState<
 43→    Record<string, boolean>
 44→  >({});
 45→  const [hoveredRuleId, setHoveredRuleId] = useState<string | null>(null);
 46→  const [disableError, setDisableError] = useState<string | null>(null);
 47→  const [promoteError, setPromoteError] = useState<string | null>(null);
 48→  const explanations = useRuleExplanations();
 49→  const invalidateRules = () =>
 50→    queryClient.invalidateQueries({ queryKey: orpc.rules.list.key() });
 51→
 52→  async function handleDisableRule(ruleId: string): Promise<boolean> {
 53→    setDisablingRuleById((c) => ({ ...c, [ruleId]: true }));
 54→    setDisableError(null);
 55→    try {
 56→      await rpc.rules.disable({ id: ruleId });
 57→      invalidateRules();
 58→      setHoveredRuleId((c) => (c === ruleId ? null : c));
 59→      return true;
 60→    } catch (error) {
 61→      setDisableError(
 62→        errorMsg(error, "Regel konnte nicht deaktiviert werden."),
 63→      );
 64→      return false;
 65→    } finally {
 66→      setDisablingRuleById((c) => removeKey(c, ruleId));
 67→    }
 68→  }
 69→
 70→  async function handleRejectLastChange(
 71→    sessionDetail: AdjustmentSessionDetail,
 72→  ): Promise<boolean> {
 73→    const findMatch = (rules: FormatRule[]) =>
 74→      rules.find(
 75→        (r) =>
 76→          r.sourceSessionId === sessionDetail.session.id &&
 77→          r.status === "active",
 78→      );
 79→    let matchingRule = findMatch(activeRules);
 80→    if (!matchingRule) {
 81→      try {
 82→        const freshRules = await rpc.rules.list({
 83→          importId: jobId,
 84→          format: view,
 85→        });
 86→        invalidateRules();
 87→        matchingRule = findMatch(freshRules);
 88→      } catch {
 89→        return false;
 90→      }
 91→    }
 92→    if (!matchingRule) return false;
 93→    return handleDisableRule(matchingRule.id);
 94→  }
 95→
 96→  async function handlePromoteRule(ruleId: string): Promise<boolean> {
 97→    setPromotingRuleById((c) => ({ ...c, [ruleId]: true }));
 98→    setPromoteError(null);
 99→    try {
100→      await promoteFormatRule(ruleId);
101→      invalidateRules();
102→      return true;
103→    } catch (error) {
104→      setPromoteError(
105→        errorMsg(error, "Regel konnte nicht hochgestuft werden."),
106→      );
107→      return false;
108→    } finally {
109→      setPromotingRuleById((c) => removeKey(c, ruleId));
110→    }
111→  }
112→
113→  async function handleDemoteRule(ruleId: string): Promise<boolean> {
114→    setPromotingRuleById((c) => ({ ...c, [ruleId]: true }));
115→    setPromoteError(null);
116→    try {
117→      await demoteFormatRule(ruleId, jobId);
118→      invalidateRules();
119→      return true;
120→    } catch (error) {
121→      setPromoteError(
122→        errorMsg(error, "Regel konnte nicht herabgestuft werden."),
123→      );
124→      return false;
125→    } finally {
126→      setPromotingRuleById((c) => removeKey(c, ruleId));
127→    }
128→  }
129→
130→  return {
131→    activeRules,
132→    disablingRuleById,
133→    promotingRuleById,
134→    hoveredRuleId,
135→    disableError,
136→    promoteError,
137→    setHoveredRuleId,
138→    clearDisableError: () => setDisableError(null),
139→    clearPromoteError: () => setPromoteError(null),
140→    handleDisableRule,
141→    handlePromoteRule,
142→    handleDemoteRule,
143→    handleRejectLastChange,
144→    ...explanations,
145→  };
146→}
