 1→import { useQuery, useQueryClient } from "@tanstack/react-query";
 2→import { useCallback, useMemo, useState } from "react";
 3→import { orpc } from "@/lib/orpc";
 4→import { rpc } from "@/lib/rpc";
 5→
 6→export function useMessageDeletion(importId: string) {
 7→  const queryClient = useQueryClient();
 8→  const [showDeleted, setShowDeleted] = useState(false);
 9→
10→  const deletionsQuery = useQuery({
11→    ...orpc.deletions.list.queryOptions({ input: { importId } }),
12→  });
13→
14→  const deletedMessageIds = useMemo(
15→    () => new Set(deletionsQuery.data?.map((d) => d.messageId)),
16→    [deletionsQuery.data],
17→  );
18→
19→  const invalidate = useCallback(() => {
20→    queryClient.invalidateQueries({ queryKey: orpc.deletions.list.key() });
21→  }, [queryClient]);
22→
23→  const deleteMessage = useCallback(
24→    async (messageId: string, reason?: string) => {
25→      const result = await rpc.deletions.delete({
26→        importId,
27→        messageId,
28→        reason,
29→      });
30→      invalidate();
31→      return result;
32→    },
33→    [importId, invalidate],
34→  );
35→
36→  const deleteRound = useCallback(
37→    async (messageId: string, reason?: string) => {
38→      const result = await rpc.deletions.deleteRound({
39→        importId,
40→        messageId,
41→        reason,
42→      });
43→      invalidate();
44→      return result;
45→    },
46→    [importId, invalidate],
47→  );
48→
49→  const restoreMessage = useCallback(
50→    async (messageId: string) => {
51→      const result = await rpc.deletions.restore({ importId, messageId });
52→      invalidate();
53→      return result;
54→    },
55→    [importId, invalidate],
56→  );
57→
58→  return {
59→    deletedMessageIds,
60→    deletionsCount: deletedMessageIds.size,
61→    isLoading: deletionsQuery.isLoading,
62→    showDeleted,
63→    setShowDeleted,
64→    deleteMessage,
65→    deleteRound,
66→    restoreMessage,
67→  };
68→}
