146→        {message.blocks.map((block, blockIndex) => {
147→          const blockText = blockToPlainText(block);
148→          const blockEffects =
149→            effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
150→          const isSelected =
151→            selectedBlock?.messageId === message.id &&
152→            selectedBlock.blockIndex === blockIndex;
153→          const isHighlighted = highlightedBlocks.has(
154→            `${message.id}:${blockIndex}`,
155→          );
156→          const emitSelection = (
157→            anchor: ViewportAnchor,
158→            selectedText: string,
159→          ) => {
160→            lastSelectionInteractionAt.current = Date.now();
161→
162→            onSelectBlock(
163→              {
164→                blockIndex,
165→                blockType: block.type,
166→                messageId: message.id,
167→                messageIndex,
168→                messageRole: message.role,
169→                selectedText,
170→                textQuote: truncateSelectionText(selectedText),
171→              },
172→              anchor,
173→            );
