  1→import type { ConversationSnapshot } from "@chat-exporter/shared";
  2→import { eq } from "drizzle-orm";
  3→import { db, withTransaction } from "../db/client.js";
  4→import { conversationSnapshots } from "../db/schema.js";
  5→
  6→type SnapshotRow = typeof conversationSnapshots.$inferSelect;
  7→
  8→function toApiSnapshot(row: SnapshotRow): ConversationSnapshot {
  9→  return {
 10→    id: row.id,
 11→    importId: row.importId,
 12→    label: row.label,
 13→    isActive: row.isActive === 1,
 14→    createdAt: row.createdAt,
 15→    updatedAt: row.updatedAt,
 16→  };
 17→}
 18→
 19→export function createSnapshot(
 20→  importId: string,
 21→  label: string,
 22→): ConversationSnapshot {
 23→  const id = crypto.randomUUID();
 24→  const now = new Date().toISOString();
 25→
 26→  db.insert(conversationSnapshots)
 27→    .values({
 28→      id,
 29→      importId,
 30→      label,
 31→      isActive: 0,
 32→      createdAt: now,
 33→      updatedAt: now,
 34→    })
 35→    .run();
 36→
 37→  return {
 38→    id,
 39→    importId,
 40→    label,
 41→    isActive: false,
 42→    createdAt: now,
 43→    updatedAt: now,
 44→  };
 45→}
 46→
 47→export function listSnapshots(importId: string): ConversationSnapshot[] {
 48→  const rows = db
 49→    .select()
 50→    .from(conversationSnapshots)
 51→    .where(eq(conversationSnapshots.importId, importId))
 52→    .orderBy(conversationSnapshots.createdAt)
 53→    .all();
 54→
 55→  return rows.map(toApiSnapshot);
 56→}
 57→
 58→export function getActiveSnapshot(
 59→  importId: string,
 60→): ConversationSnapshot | null {
 61→  const row = db
 62→    .select()
 63→    .from(conversationSnapshots)
 64→    .where(eq(conversationSnapshots.importId, importId))
 65→    .all()
 66→    .find((r) => r.isActive === 1);
 67→
 68→  return row ? toApiSnapshot(row) : null;
 69→}
 70→
 71→export function activateSnapshot(snapshotId: string): ConversationSnapshot {
 72→  return withTransaction(() => {
 73→    const snapshot = db
 74→      .select()
 75→      .from(conversationSnapshots)
 76→      .where(eq(conversationSnapshots.id, snapshotId))
 77→      .get();
 78→
 79→    if (!snapshot) {
 80→      throw new Error(`Snapshot not found: ${snapshotId}`);
 81→    }
 82→
 83→    const now = new Date().toISOString();
 84→
 85→    // Deactivate all snapshots of the same import
 86→    db.update(conversationSnapshots)
 87→      .set({ isActive: 0, updatedAt: now })
 88→      .where(eq(conversationSnapshots.importId, snapshot.importId))
 89→      .run();
 90→
 91→    // Activate this snapshot
 92→    db.update(conversationSnapshots)
 93→      .set({ isActive: 1, updatedAt: now })
 94→      .where(eq(conversationSnapshots.id, snapshotId))
 95→      .run();
 96→
 97→    const updated = db
 98→      .select()
 99→      .from(conversationSnapshots)
100→      .where(eq(conversationSnapshots.id, snapshotId))
101→      .get();
102→
103→    if (!updated) {
104→      throw new Error(`Snapshot not found after activation: ${snapshotId}`);
105→    }
106→
107→    return toApiSnapshot(updated);
108→  });
109→}
110→
111→export function deactivateAllSnapshots(importId: string): void {
112→  withTransaction(() => {
113→    const now = new Date().toISOString();
114→    db.update(conversationSnapshots)
115→      .set({ isActive: 0, updatedAt: now })
116→      .where(eq(conversationSnapshots.importId, importId))
117→      .run();
118→  });
119→}
120→
121→export function deleteSnapshot(snapshotId: string): boolean {
122→  const result = db
123→    .delete(conversationSnapshots)
124→    .where(eq(conversationSnapshots.id, snapshotId))
125→    .run();
126→
127→  return result.changes > 0;
128→}
129→
130→export function renameSnapshot(
131→  snapshotId: string,
132→  label: string,
133→): ConversationSnapshot {
134→  const now = new Date().toISOString();
135→
136→  db.update(conversationSnapshots)
137→    .set({ label, updatedAt: now })
138→    .where(eq(conversationSnapshots.id, snapshotId))
139→    .run();
140→
141→  const updated = db
142→    .select()
143→    .from(conversationSnapshots)
144→    .where(eq(conversationSnapshots.id, snapshotId))
145→    .get();
146→
147→  if (!updated) {
148→    throw new Error(`Snapshot not found: ${snapshotId}`);
149→  }
150→
151→  return toApiSnapshot(updated);
152→}
