  1→import type { Block, Conversation } from "@chat-exporter/shared";
  2→
  3→function escapePipe(value: string) {
  4→  return value.replaceAll("|", "\\|");
  5→}
  6→
  7→function blocksToWords(blocks: Block[]) {
  8→  return blocks.reduce((count, block) => {
  9→    const text =
 10→      block.type === "table"
 11→        ? `${block.headers.join(" ")} ${block.rows.flat().join(" ")}`
 12→        : block.type === "list"
 13→          ? block.items.join(" ")
 14→          : block.text;
 15→
 16→    const words = text.trim().split(/\s+/).filter(Boolean).length;
 17→    return count + words;
 18→  }, 0);
 19→}
 20→
 21→export function conversationToMarkdown(conversation: Conversation) {
 22→  return conversation.messages
 23→    .map((message) => {
 24→      const heading =
 25→        message.role.charAt(0).toUpperCase() + message.role.slice(1);
 26→      const body = message.blocks
 27→        .map((block) => {
 28→          switch (block.type) {
 29→            case "paragraph":
 30→              return block.text;
 31→            case "heading":
 32→              return `${"#".repeat(block.level)} ${block.text}`;
 33→            case "list":
 34→              return block.items
 35→                .map((item, index) =>
 36→                  block.ordered ? `${index + 1}. ${item}` : `- ${item}`,
 37→                )
 38→                .join("\n");
 39→            case "quote":
 40→              return block.text
 41→                .split("\n")
 42→                .map((line) => `> ${line}`)
 43→                .join("\n");
 44→            case "code":
 45→              return `\`\`\`${block.language}\n${block.text}\n\`\`\``;
 46→            case "table": {
 47→              const header = `| ${block.headers.map(escapePipe).join(" | ")} |`;
 48→              const divider = `| ${block.headers.map(() => "---").join(" | ")} |`;
 49→              const rows = block.rows.map(
 50→                (row) => `| ${row.map(escapePipe).join(" | ")} |`,
 51→              );
 52→              return [header, divider, ...rows].join("\n");
 53→            }
 54→          }
 55→        })
 56→        .join("\n\n");
 57→
 58→      return `## ${heading}\n\n${body}`;
 59→    })
 60→    .join("\n\n");
 61→}
 62→
 63→export function conversationToHandover(conversation: Conversation) {
 64→  const transcript = conversation.messages
 65→    .map((message) => {
 66→      const label = message.role.toUpperCase();
 67→      const body = message.blocks
 68→        .map((block) => {
 69→          switch (block.type) {
 70→            case "paragraph":
 71→            case "quote":
 72→              return block.text;
 73→            case "heading":
 74→              return block.text;
 75→            case "list":
 76→              return block.items.map((item) => `- ${item}`).join("\n");
 77→            case "code":
 78→              return `${block.language} code:\n${block.text}`;
 79→            case "table":
 80→              return [
 81→                block.headers.join(" | "),
 82→                ...block.rows.map((row) => row.join(" | ")),
 83→              ].join("\n");
 84→          }
 85→        })
 86→        .join("\n\n");
 87→
 88→      return `[${label}]\n${body}`;
 89→    })
 90→    .join("\n\n");
 91→
 92→  return `${transcript}\n\n[USER]\nContinue from this imported transcript and preserve the existing context and structure.`;
 93→}
 94→
 95→export function conversationWordCount(conversation: Conversation) {
 96→  return conversation.messages.reduce(
 97→    (count, message) => count + blocksToWords(message.blocks),
 98→    0,
 99→  );
100→}
