import type { Block, Message } from "@chat-exporter/shared";

// ---------------------------------------------------------------------------
// Block → Markdown
// ---------------------------------------------------------------------------

function blockToMarkdown(block: Block): string {
  switch (block.type) {
    case "paragraph":
      return block.text;
    case "heading":
      return `${"#".repeat(block.level)} ${block.text}`;
    case "code":
      return `\`\`\`${block.language}\n${block.text}\n\`\`\``;
    case "list":
      return block.items
        .map((item, i) => (block.ordered ? `${i + 1}. ${item}` : `- ${item}`))
        .join("\n");
    case "quote":
      return `> ${block.text}`;
    case "table": {
      const header = `| ${block.headers.join(" | ")} |`;
      const separator = `| ${block.headers.map(() => "---").join(" | ")} |`;
      const rows = block.rows
        .map((row) => `| ${row.join(" | ")} |`)
        .join("\n");
      return `${header}\n${separator}\n${rows}`;
    }
  }
}

// ---------------------------------------------------------------------------
// Block → HTML (for reader clipboard)
// ---------------------------------------------------------------------------

function blockToHtml(block: Block): string {
  switch (block.type) {
    case "paragraph":
      return `<p style="margin:0 0 0.75em">${escapeHtml(block.text)}</p>`;
    case "heading": {
      const tag = `h${block.level}` as const;
      return `<${tag} style="margin:0 0 0.5em">${escapeHtml(block.text)}</${tag}>`;
    }
    case "code":
      return `<pre style="margin:0 0 0.75em;padding:0.75em;background:#f5f5f5;border-radius:6px;overflow-x:auto"><code>${escapeHtml(block.text)}</code></pre>`;
    case "list": {
      const tag = block.ordered ? "ol" : "ul";
      const items = block.items
        .map((item) => `<li>${escapeHtml(item)}</li>`)
        .join("");
      return `<${tag} style="margin:0 0 0.75em;padding-left:1.5em">${items}</${tag}>`;
    }
    case "quote":
      return `<blockquote style="margin:0 0 0.75em;padding-left:1em;border-left:3px solid #ddd;color:#555">${escapeHtml(block.text)}</blockquote>`;
    case "table": {
      const headerCells = block.headers
        .map(
          (h) =>
            `<th style="border:1px solid #ddd;padding:4px 8px">${escapeHtml(h)}</th>`,
        )
        .join("");
      const rows = block.rows
        .map(
          (row) =>
            `<tr>${row.map((cell) => `<td style="border:1px solid #ddd;padding:4px 8px">${escapeHtml(cell)}</td>`).join("")}</tr>`,
        )
        .join("");
      return `<table style="margin:0 0 0.75em;border-collapse:collapse"><thead><tr>${headerCells}</tr></thead><tbody>${rows}</tbody></table>`;
    }
  }
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

// ---------------------------------------------------------------------------
// Block → Plain text (for handover)
// ---------------------------------------------------------------------------

function blockToPlainText(block: Block): string {
  switch (block.type) {
    case "paragraph":
    case "heading":
    case "quote":
      return block.text;
    case "code":
      return block.text;
    case "list":
      return block.items.join("\n");
    case "table":
      return [block.headers.join("\t"), ...block.rows.map((r) => r.join("\t"))].join("\n");
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export async function copyMessageToClipboard(
  message: Message,
  format: "reader" | "markdown" | "json" | "handover",
  blocks: Block[],
): Promise<void> {
  switch (format) {
    case "reader": {
      const html = blocks.map(blockToHtml).join("\n");
      const blob = new Blob([html], { type: "text/html" });
      const item = new ClipboardItem({ "text/html": blob });
      await navigator.clipboard.write([item]);
      break;
    }
    case "markdown": {
      const md = blocks.map(blockToMarkdown).join("\n\n");
      await navigator.clipboard.writeText(md);
      break;
    }
    case "json": {
      const json = JSON.stringify(message, null, 2);
      await navigator.clipboard.writeText(json);
      break;
    }
    case "handover": {
      const text = blocks.map(blockToPlainText).join("\n\n");
      await navigator.clipboard.writeText(text);
      break;
    }
  }
}

import { renderHook } from "@testing-library/react";
import { describe, expect, test } from "vitest";

import type { Block, Conversation } from "@chat-exporter/shared";

import { useResolvedConversation } from "./use-resolved-conversation";

function createConversation(
  messages: Array<{ id: string; role: "user" | "assistant"; blocks: Block[] }>,
): Conversation {
  return {
    id: "conv-1",
    title: "Test Conversation",
    source: { url: "https://example.com/chat", platform: "chatgpt" },
    messages,
  };
}

function textBlock(text: string): Block {
  return { type: "paragraph", text };
}

describe("useResolvedConversation", () => {
  test("returns original messages when editedMessagesMap is empty", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Hi there")] },
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current).toHaveLength(2);
    expect(result.current.at(0)?.blocks).toEqual([textBlock("Hello")]);
    expect(result.current.at(1)?.blocks).toEqual([textBlock("Hi there")]);
  });

  test("marks non-edited messages with isEdited: false", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current.at(0)?.isEdited).toBe(false);
  });

  test("replaces blocks for edited messages", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Original")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Original reply")] },
    ]);
    const editedBlocks: Block[] = [textBlock("Edited content")];
    const editsMap = new Map<string, Block[]>([["m1", editedBlocks]]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current.at(0)?.blocks).toEqual([textBlock("Edited content")]);
    expect(result.current.at(1)?.blocks).toEqual([textBlock("Original reply")]);
  });

  test("marks edited messages with isEdited: true", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Original")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Reply")] },
    ]);
    const editsMap = new Map<string, Block[]>([
      ["m1", [textBlock("Edited")]],
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current.at(0)?.isEdited).toBe(true);
    expect(result.current.at(1)?.isEdited).toBe(false);
  });

  test("handles undefined conversation gracefully", () => {
    const { result } = renderHook(() =>
      useResolvedConversation(undefined, new Map()),
    );

    expect(result.current).toEqual([]);
  });

  test("handles empty messages array", () => {
    const conversation = createConversation([]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current).toEqual([]);
  });

  test("preserves message id and role in resolved output", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);
    const editsMap = new Map<string, Block[]>([
      ["m1", [textBlock("Edited")]],
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current.at(0)?.id).toBe("m1");
    expect(result.current.at(0)?.role).toBe("user");
  });

  test("memoizes result when inputs do not change", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);
    const editsMap = new Map<string, Block[]>();

    const { result, rerender } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    const firstResult = result.current;
    rerender();
    expect(result.current).toBe(firstResult);
  });
});

