import type { Block, Conversation } from "@chat-exporter/shared";
import { describe, expect, test } from "vitest";
import {
  type MessageEditEntry,
  mergeEditsIntoConversation,
} from "./conversation-merge.js";

function createConversation(
  overrides: Partial<Conversation> = {},
): Conversation {
  return {
    id: "conv-1",
    title: "Test Conversation",
    source: { url: "https://chatgpt.com/share/abc", platform: "chatgpt" },
    messages: [
      {
        id: "msg-1",
        role: "user",
        blocks: [{ type: "paragraph", text: "Hello" }],
      },
      {
        id: "msg-2",
        role: "assistant",
        blocks: [
          { type: "paragraph", text: "Hi there" },
          { type: "code", language: "typescript", text: "const x = 1;" },
        ],
      },
      {
        id: "msg-3",
        role: "user",
        blocks: [{ type: "paragraph", text: "Thanks" }],
      },
    ],
    ...overrides,
  };
}

function createEditEntry(
  messageId: string,
  blocks: Block[],
  overrides: Partial<MessageEditEntry> = {},
): MessageEditEntry {
  return {
    messageId,
    editedBlocksJson: JSON.stringify(blocks),
    ...overrides,
  };
}

describe("mergeEditsIntoConversation", () => {
  test("returns original conversation unchanged when edits are empty", () => {
    const conversation = createConversation();

    const result = mergeEditsIntoConversation(conversation, []);

    expect(result).toBe(conversation);
  });

  test("replaces blocks for a matching message", () => {
    const conversation = createConversation();
    const newBlocks: Block[] = [
      { type: "paragraph", text: "Edited greeting" },
    ];
    const edits = [createEditEntry("msg-1", newBlocks)];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0]?.blocks).toEqual(newBlocks);
  });

  test("leaves non-matching messages unchanged", () => {
    const conversation = createConversation();
    const newBlocks: Block[] = [
      { type: "paragraph", text: "Edited greeting" },
    ];
    const edits = [createEditEntry("msg-1", newBlocks)];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[1]?.blocks).toEqual(conversation.messages[1]?.blocks);
    expect(result.messages[2]?.blocks).toEqual(conversation.messages[2]?.blocks);
  });

  test("applies multiple edits to different messages", () => {
    const conversation = createConversation();
    const editedBlocks1: Block[] = [
      { type: "paragraph", text: "Edited user msg" },
    ];
    const editedBlocks2: Block[] = [
      { type: "heading", level: 2, text: "New heading" },
      { type: "paragraph", text: "Edited assistant response" },
    ];
    const edits = [
      createEditEntry("msg-1", editedBlocks1),
      createEditEntry("msg-2", editedBlocks2),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0]?.blocks).toEqual(editedBlocks1);
    expect(result.messages[1]?.blocks).toEqual(editedBlocks2);
    expect(result.messages[2]?.blocks).toEqual(conversation.messages[2]?.blocks);
  });

  test("does not mutate the original conversation", () => {
    const conversation = createConversation();
    const originalFirstBlocks = conversation.messages[0]?.blocks;
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "Changed" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(conversation.messages[0]?.blocks).toBe(originalFirstBlocks);
    expect(result).not.toBe(conversation);
    expect(result.messages).not.toBe(conversation.messages);
  });

  test("preserves conversation metadata when edits are applied", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "Changed" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.id).toBe(conversation.id);
    expect(result.title).toBe(conversation.title);
    expect(result.source).toBe(conversation.source);
  });

  test("ignores edits for non-existent message IDs", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("non-existent-id", [
        { type: "paragraph", text: "Ghost edit" },
      ]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages).toEqual(conversation.messages);
  });

  test("last edit wins when duplicate messageIds exist", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "First edit" }]),
      createEditEntry("msg-1", [{ type: "paragraph", text: "Second edit" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0]?.blocks).toEqual([
      { type: "paragraph", text: "Second edit" },
    ]);
  });
});

import {
  Download,
  Eye,
  EyeOff,
  History,
  Pencil,
  Settings2,
} from "lucide-react";

import {
  adjustmentLabels,
  getAdjustViewLabel,
  getEndAdjustLabel,
  getViewLabel,
} from "@/components/format-workspace/labels";
import { RulesListModal } from "@/components/format-workspace/rules-list-modal";
import type { EditMode, ViewMode } from "@/components/format-workspace/types";
import type { useFormatRules } from "@/components/format-workspace/use-format-rules";
import { Button } from "@/components/ui/button";

const outputViews: { value: ViewMode; label: string }[] = [
  { value: "reader", label: getViewLabel("reader") },
  { value: "markdown", label: getViewLabel("markdown") },
  { value: "handover", label: getViewLabel("handover") },
  { value: "json", label: getViewLabel("json") },
];

type CompletedToolbarProps = {
  adjustModeEnabled: boolean;
  deletionsCount?: number;
  editMode: EditMode;
  isAdjustableView: boolean;
  rules: ReturnType<typeof useFormatRules>;
  showDeleted?: boolean;
  snapshotCount?: number;
  view: ViewMode;
  onDownloadMarkdown?: () => void;
  onEditModeChange: (mode: EditMode) => void;
  onToggleAdjustMode: () => void;
  onToggleShowDeleted?: () => void;
  onVersionsClick?: () => void;
  onViewChange: (view: ViewMode) => void;
};

export function CompletedToolbar({
  adjustModeEnabled,
  deletionsCount,
  editMode,
  isAdjustableView,
  rules,
  showDeleted,
  snapshotCount,
  view,
  onDownloadMarkdown,
  onEditModeChange,
  onToggleAdjustMode,
  onToggleShowDeleted,
  onVersionsClick,
  onViewChange,
}: CompletedToolbarProps) {
  return (
    <div className="space-y-2">
      {/* Row 1: Format buttons */}
      <div data-testid="toolbar-format-row" className="flex flex-wrap gap-2">
        {outputViews.map((outputView) => (
          <Button
            key={outputView.value}
            data-testid={`format-view-${outputView.value}`}
            type="button"
            size="sm"
            variant={view === outputView.value ? "default" : "outline"}
            onClick={() => onViewChange(outputView.value)}
          >
            {outputView.label}
          </Button>
        ))}
      </div>

      {/* Row 2: Action buttons */}
      <div
        data-testid="toolbar-action-row"
        className="flex flex-wrap items-center gap-2"
      >
        {onDownloadMarkdown ? (
          <Button
            data-testid="toolbar-download"
            type="button"
            size="sm"
            variant="outline"
            onClick={onDownloadMarkdown}
          >
            <Download className="mr-2 h-4 w-4" />
            {adjustmentLabels.downloadAction}
          </Button>
        ) : (
          <Button
            data-testid="toolbar-download"
            type="button"
            size="sm"
            variant="outline"
            disabled
          >
            <Download className="mr-2 h-4 w-4" />
            {adjustmentLabels.downloadAction}
          </Button>
        )}

        {snapshotCount && snapshotCount > 0 ? (
          <Button
            data-testid="toolbar-versions"
            type="button"
            size="sm"
            variant="outline"
            onClick={onVersionsClick}
          >
            <History className="mr-2 h-4 w-4" />
            {adjustmentLabels.versions}
          </Button>
        ) : null}

        {deletionsCount && deletionsCount > 0 ? (
          <Button
            type="button"
            size="sm"
            variant={showDeleted ? "default" : "outline"}
            onClick={onToggleShowDeleted}
          >
            {showDeleted ? (
              <EyeOff className="mr-2 h-4 w-4" />
            ) : (
              <Eye className="mr-2 h-4 w-4" />
            )}
            {showDeleted
              ? "Gelöschte ausblenden"
              : `${deletionsCount} gelöscht`}
          </Button>
        ) : null}

        {isAdjustableView ? (
          <>
            <RulesListModal
              disablingRuleById={rules.disablingRuleById}
              expandedRuleId={rules.expandedRuleId}
              explanationErrorById={rules.explanationErrorById}
              explanationLoadingById={rules.explanationLoadingById}
              promotingRuleById={rules.promotingRuleById}
              rules={rules.activeRules}
              view={view}
              getExplanationDetail={rules.getExplanationDetail}
              onDemoteRule={(ruleId) => {
                void rules.handleDemoteRule(ruleId);
              }}
              onDisableRule={(ruleId) => {
                void rules.handleDisableRule(ruleId);
              }}
              onHoverRule={(ruleId) => rules.setHoveredRuleId(ruleId)}
              onLeaveRule={() => rules.setHoveredRuleId(null)}
              onPromoteRule={(ruleId) => {
                void rules.handlePromoteRule(ruleId);
              }}
              onToggleRuleExplanation={rules.handleToggleRuleExplanation}
            />
            <Button
              data-testid={`toggle-adjust-mode-${view}`}
              type="button"
              size="sm"
              variant={adjustModeEnabled ? "default" : "outline"}
              onClick={onToggleAdjustMode}
            >
              <Settings2 className="mr-2 h-4 w-4" />
              {adjustModeEnabled
                ? getEndAdjustLabel()
                : getAdjustViewLabel(view)}
            </Button>
          </>
        ) : null}

        {view === "reader" ? (
          <Button
            data-testid="toggle-edit-mode"
            type="button"
            size="sm"
            variant={editMode === "edit" ? "default" : "outline"}
            onClick={() =>
              onEditModeChange(editMode === "edit" ? "view" : "edit")
            }
          >
            <Pencil className="mr-2 h-4 w-4" />
            {editMode === "edit"
              ? adjustmentLabels.endEdit
              : adjustmentLabels.edit}
          </Button>
        ) : null}
      </div>
    </div>
  );
}

