169→            effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
170→          const isSelected =
171→            selectedBlock?.messageId === message.id &&
172→            selectedBlock.blockIndex === blockIndex;
173→          const isHighlighted = highlightedBlocks.has(
174→            `${message.id}:${blockIndex}`,
175→          );
