177→            anchor: ViewportAnchor,
178→            selectedText: string,
179→          ) => {
180→            lastSelectionInteractionAt.current = Date.now();
181→
182→            onSelectBlock(
183→              {
184→                blockIndex,
185→                blockType: block.type,
186→                messageId: message.id,
187→                messageIndex,
188→                messageRole: message.role,
189→                selectedText,
