211→                  effects: blockEffects,
212→                  isHighlighted,
213→                  isSelected,
214→                })}
215→                style={getReaderBlockStyle(blockEffects)}
216→                data-selected={isSelected ? "true" : "false"}
217→                onPointerUp={(event) => {
218→                  if (!adjustModeEnabled) {
219→                    return;
220→                  }
221→
222→                  const selection = window.getSelection();
223→                  const range =
224→                    selection && selection.rangeCount > 0
225→                      ? selection.getRangeAt(0)
226→                      : null;
227→                  const selectedText = selection?.toString().trim() ?? "";
228→                  const container = event.currentTarget;
229→                  const rangeStartContainer = range?.startContainer ?? null;
230→                  const rangeEndContainer = range?.endContainer ?? null;
231→                  const hasLocalTextSelection =
232→                    Boolean(selectedText) &&
233→                    Boolean(rangeStartContainer) &&
234→                    Boolean(rangeEndContainer) &&
235→                    container.contains(rangeStartContainer) &&
236→                    container.contains(rangeEndContainer);
237→                  const anchorRect =
238→                    hasLocalTextSelection && range
239→                      ? range.getBoundingClientRect()
240→                      : container.getBoundingClientRect();
241→
242→                  emitSelection(
