289→export function ReaderView({
290→  activeRules,
291→  adjustModeEnabled,
292→  conversation,
293→  deletedMessageIds,
294→  effectsMap,
295→  highlightedRuleId,
296→  onCopyMessage,
297→  onDeleteMessage,
298→  onDeleteRound,
299→  onRestoreMessage,
300→  onSelectBlock,
301→  selectedBlock,
302→  showDeleted,
303→}: ReaderViewProps) {
304→  const visibleMessages = useMemo(() => {
305→    if (!conversation?.messages) return [];
306→    if (!deletedMessageIds?.size) return conversation.messages;
307→    if (showDeleted) return conversation.messages;
308→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
309→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
310→
311→  const highlightedBlocks = useMemo(() => {
312→    if (!highlightedRuleId || !conversation) {
313→      return new Set<string>();
314→    }
315→
316→    const rule = activeRules.find(
317→      (r) => r.id === highlightedRuleId && r.status === "active",
318→    );
319→
320→    if (!rule) {
321→      return new Set<string>();
322→    }
323→
324→    const matches = getBlocksMatchingRule(rule, conversation);
325→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
326→  }, [highlightedRuleId, activeRules, conversation]);
327→
328→  if (!conversation?.messages.length) {
329→    return (
330→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
331→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
332→      </div>
333→    );
334→  }
335→
336→  return (
337→    <div className="space-y-3">
338→      {visibleMessages.map((message, index) => (
339→        <ReaderMessage
340→          key={message.id}
341→          adjustModeEnabled={adjustModeEnabled}
342→          effectsMap={effectsMap}
343→          highlightedBlocks={highlightedBlocks}
344→          message={message}
345→          messageIndex={index}
346→          onCopyMessage={
347→            onCopyMessage ? () => onCopyMessage(message.id) : undefined
348→          }
349→          onSelectBlock={onSelectBlock}
350→          selectedBlock={selectedBlock}
351→          isDeleted={deletedMessageIds?.has(message.id)}
352→          onDeleteMessage={
353→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
354→          }
355→          onDeleteRound={
356→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
357→          }
358→          onRestore={
359→            onRestoreMessage
360→              ? () => {
361→                  void onRestoreMessage(message.id);
362→                }
363→              : undefined
364→          }
365→        />
366→      ))}
367→    </div>
368→  );
369→}
