 47→type ReaderViewProps = {
 48→  activeRules: FormatRule[];
 49→  adjustModeEnabled: boolean;
 50→  conversation: Conversation | undefined;
 51→  deletedMessageIds?: Set<string>;
 52→  editMode?: boolean;
 53→  effectsMap: Map<string, RuleEffect[]>;
