105→const ReaderMessage = memo(function ReaderMessage({
106→  adjustModeEnabled,
107→  editMode,
108→  effectsMap,
109→  highlightedBlocks,
110→  isDeleted,
111→  message,
112→  messageIndex,
113→  onBlockChange,
114→  onCopyMessage,
115→  onDeleteMessage,
116→  onDeleteRound,
117→  onRestore,
118→  onSelectBlock,
119→  selectedBlock,
120→}: ReaderMessageProps) {
121→  const lastSelectionInteractionAt = useRef(0);
122→
123→  return (
124→    <article
125→      className={cn(
126→        "rounded-[1.55rem] border border-border/80 px-4 py-5 sm:px-5",
127→        message.role === "assistant" ? "bg-card/92" : "bg-secondary/30",
128→        isDeleted && "opacity-50",
129→      )}
130→    >
131→      {isDeleted && (
132→        <div className="mb-3 flex items-center justify-between rounded-xl bg-red-50 border border-red-200/60 px-3 py-2 text-xs text-red-700">
133→          <span>Gelöscht</span>
134→          {onRestore && (
135→            <button
136→              type="button"
137→              className="text-red-600 hover:text-red-800 underline"
138→              onClick={(e) => {
139→                e.stopPropagation();
140→                onRestore();
141→              }}
142→            >
143→              Wiederherstellen
144→            </button>
145→          )}
146→        </div>
147→      )}
148→      <div className="mb-4 flex items-center gap-3 text-xs uppercase tracking-[0.18em] text-muted-foreground">
149→        <span>{getRoleLabel(message.role)}</span>
150→        <span>{messageIndex + 1}</span>
151→        {!isDeleted && (onDeleteMessage || onCopyMessage) && (
152→          <span className="ml-auto flex items-center gap-1">
153→            {onCopyMessage && (
154→              <button
155→                type="button"
156→                className="rounded-lg p-1.5 text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-colors"
157→                onClick={(e) => {
158→                  e.stopPropagation();
159→                  onCopyMessage();
160→                }}
161→                aria-label="Nachricht kopieren"
162→                data-testid={`copy-message-${message.id}`}
163→              >
164→                <ClipboardCopy className="h-4 w-4" />
165→              </button>
166→            )}
167→            {onDeleteMessage && onDeleteRound && (
168→              <MessageDeleteMenu
169→                onDeleteMessage={onDeleteMessage}
170→                onDeleteRound={onDeleteRound}
171→              />
172→            )}
173→          </span>
174→        )}
175→      </div>
176→      <div className="space-y-4">
177→        {message.blocks.map((block, blockIndex) => {
178→          const blockText = blockToPlainText(block);
179→          const blockEffects =
180→            effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
181→          const isSelected =
182→            selectedBlock?.messageId === message.id &&
183→            selectedBlock.blockIndex === blockIndex;
184→          const isHighlighted = highlightedBlocks.has(
185→            `${message.id}:${blockIndex}`,
186→          );
187→          const emitSelection = (
188→            anchor: ViewportAnchor,
189→            selectedText: string,
190→          ) => {
191→            lastSelectionInteractionAt.current = Date.now();
192→
193→            onSelectBlock(
194→              {
195→                blockIndex,
196→                blockType: block.type,
197→                messageId: message.id,
198→                messageIndex,
199→                messageRole: message.role,
200→                selectedText,
201→                textQuote: truncateSelectionText(selectedText),
202→              },
203→              anchor,
204→            );
205→          };
206→
207→          const inserts = collectInserts(blockEffects);
208→
209→          return (
210→            // biome-ignore lint/suspicious/noArrayIndexKey: block identity is message.id + blockIndex
211→            <React.Fragment key={`${message.id}-${blockIndex}`}>
212→              {inserts.insertBefore === "hr" && (
213→                <hr className="border-border/40" />
214→              )}
215→              {inserts.insertBefore === "spacer" && <div className="h-6" />}
216→              {/* biome-ignore lint/a11y/useKeyWithClickEvents: block selection is pointer-only by design */}
217→              {/* biome-ignore lint/a11y/noStaticElementInteractions: block selection uses onPointerUp + onClick */}
218→              <div
219→                data-testid={`reader-block-${message.id}-${blockIndex}`}
220→                className={getReaderBlockClassName({
221→                  adjustModeEnabled,
222→                  effects: blockEffects,
223→                  isHighlighted,
224→                  isSelected,
225→                })}
226→                style={getReaderBlockStyle(blockEffects)}
227→                data-selected={isSelected ? "true" : "false"}
228→                onPointerUp={(event) => {
229→                  if (!adjustModeEnabled) {
230→                    return;
231→                  }
232→
233→                  const selection = window.getSelection();
234→                  const range =
235→                    selection && selection.rangeCount > 0
236→                      ? selection.getRangeAt(0)
237→                      : null;
238→                  const selectedText = selection?.toString().trim() ?? "";
239→                  const container = event.currentTarget;
240→                  const rangeStartContainer = range?.startContainer ?? null;
241→                  const rangeEndContainer = range?.endContainer ?? null;
242→                  const hasLocalTextSelection =
243→                    Boolean(selectedText) &&
244→                    Boolean(rangeStartContainer) &&
245→                    Boolean(rangeEndContainer) &&
246→                    container.contains(rangeStartContainer) &&
247→                    container.contains(rangeEndContainer);
248→                  const anchorRect =
249→                    hasLocalTextSelection && range
250→                      ? range.getBoundingClientRect()
251→                      : container.getBoundingClientRect();
252→
253→                  emitSelection(
254→                    toViewportAnchor(anchorRect),
255→                    hasLocalTextSelection ? selectedText : blockText,
256→                  );
257→
258→                  if (selection && hasLocalTextSelection) {
259→                    selection.removeAllRanges();
260→                  }
261→                }}
262→                onClick={(event) => {
263→                  if (!adjustModeEnabled) {
264→                    return;
265→                  }
266→
267→                  if (
268→                    Date.now() - lastSelectionInteractionAt.current <
269→                    SELECTION_DEBOUNCE_MS
270→                  ) {
271→                    return;
272→                  }
273→
274→                  emitSelection(
275→                    toViewportAnchor(
276→                      event.currentTarget.getBoundingClientRect(),
277→                    ),
278→                    blockText,
279→                  );
280→                }}
281→              >
282→                <ErrorBoundary
283→                  fallback={<BlockErrorFallback blockType={block.type} />}
284→                >
285→                  {editMode && onBlockChange ? (
286→                    <EditableBlock
287→                      block={block}
288→                      blockIndex={blockIndex}
289→                      messageId={message.id}
290→                      onBlockChange={onBlockChange}
291→                    >
292→                      <BlockRenderer block={block} effects={blockEffects} />
293→                    </EditableBlock>
294→                  ) : (
295→                    <BlockRenderer block={block} effects={blockEffects} />
296→                  )}
297→                </ErrorBoundary>
298→              </div>
299→              {inserts.insertAfter === "hr" && (
300→                <hr className="border-border/40" />
301→              )}
302→              {inserts.insertAfter === "spacer" && <div className="h-6" />}
303→            </React.Fragment>
304→          );
305→        })}
306→      </div>
307→    </article>
308→  );
309→});
310→
311→export function ReaderView({
312→  activeRules,
313→  adjustModeEnabled,
314→  conversation,
315→  deletedMessageIds,
316→  editMode,
317→  effectsMap,
318→  highlightedRuleId,
319→  onBlocksChange,
320→  onCopyMessage,
321→  onDeleteMessage,
322→  onDeleteRound,
323→  onRestoreMessage,
324→  onSelectBlock,
325→  selectedBlock,
326→  showDeleted,
327→}: ReaderViewProps) {
328→  const visibleMessages = useMemo(() => {
329→    if (!conversation?.messages) return [];
330→    if (!deletedMessageIds?.size) return conversation.messages;
331→    if (showDeleted) return conversation.messages;
332→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
333→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
334→
335→  const highlightedBlocks = useMemo(() => {
336→    if (!highlightedRuleId || !conversation) {
337→      return new Set<string>();
338→    }
339→
340→    const rule = activeRules.find(
341→      (r) => r.id === highlightedRuleId && r.status === "active",
342→    );
343→
344→    if (!rule) {
345→      return new Set<string>();
346→    }
347→
348→    const matches = getBlocksMatchingRule(rule, conversation);
349→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
350→  }, [highlightedRuleId, activeRules, conversation]);
351→
352→  const handleBlockChange = useCallback(
353→    (messageId: string, blockIndex: number, newBlock: Block) => {
354→      if (!onBlocksChange || !conversation) return;
355→      const message = conversation.messages.find((m) => m.id === messageId);
356→      if (!message) return;
357→      const updatedBlocks = message.blocks.map((b, i) =>
358→        i === blockIndex ? newBlock : b,
359→      );
360→      onBlocksChange(messageId, updatedBlocks);
361→    },
362→    [onBlocksChange, conversation],
363→  );
364→
365→  if (!conversation?.messages.length) {
366→    return (
367→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
368→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
369→      </div>
370→    );
371→  }
372→
373→  return (
374→    <div className="space-y-3">
375→      {visibleMessages.map((message, index) => (
376→        <ReaderMessage
377→          key={message.id}
378→          adjustModeEnabled={adjustModeEnabled}
379→          editMode={editMode}
380→          effectsMap={effectsMap}
381→          highlightedBlocks={highlightedBlocks}
382→          message={message}
383→          messageIndex={index}
384→          onBlockChange={editMode ? handleBlockChange : undefined}
385→          onCopyMessage={
386→            onCopyMessage ? () => onCopyMessage(message.id) : undefined
387→          }
388→          onSelectBlock={onSelectBlock}
389→          selectedBlock={selectedBlock}
390→          isDeleted={deletedMessageIds?.has(message.id)}
391→          onDeleteMessage={
392→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
393→          }
394→          onDeleteRound={
395→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
396→          }
397→          onRestore={
398→            onRestoreMessage
399→              ? () => {
400→                  void onRestoreMessage(message.id);
401→                }
402→              : undefined
403→          }
404→        />
405→      ))}
406→    </div>
407→  );
408→}
